queries.sparql:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?brand_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasBrands ?child ; p:hasAgricultural_Machinery_Stores ?parent . } GROUP BY ?child }
  ?child p:name ?brand_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Agricultural_Machinery_Stores } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?brand_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasBrands ?child ; p:hasAgricultural_Machinery_Stores ?parent . } GROUP BY ?child }
  ?child p:name ?brand_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Agricultural_Machinery_Stores } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?store_name ?brand_name WHERE {
  ?stores_brands a :Stores_Brands .
  ?brands a :Brands .
  ?stores_brands p:hasBrands ?brands .
  ?agricultural_machinery_stores a :Agricultural_Machinery_Stores .
  ?stores_brands p:hasAgricultural_Machinery_Stores ?agricultural_machinery_stores .
  ?agricultural_machinery_stores p:name ?store_name .
  ?brands p:name ?brand_name .
} }
}
